CREATE TABLE CityBudget (BudgetID INT PRIMARY KEY, Department VARCHAR(50), BudgetAmount DECIMAL(10, 2)); INSERT INTO CityBudget (BudgetID, Department, BudgetAmount) VALUES (1, 'Public Works', 250000.00), (2, 'Education', 750000.00), (3, 'Parks and Recreation', 150000.00);
Q: What is the current budget for the Education department?
A: SELECT BudgetAmount FROM CityBudget WHERE Department = 'Education';

CREATE TABLE digital_divide_stats (region VARCHAR(50), issue VARCHAR(50), last_update DATETIME);
Q: Add a new row to the 'digital_divide_stats' table with the following data: 'Rural India', 'Limited internet access', '2022-01-01'
A: INSERT INTO digital_divide_stats (region, issue, last_update) VALUES ('Rural India', 'Limited internet access', '2022-01-01');

CREATE TABLE criminal_cases_tx (id INT, case_id INT, appearance_date DATE); INSERT INTO criminal_cases_tx (id, case_id, appearance_date) VALUES (1, 1001, '2019-01-01'), (2, 1001, '2019-02-01'), (3, 1002, '2019-03-01');
Q: What is the minimum number of court appearances required for criminal cases in Texas in 2019?
A: SELECT MIN(id) FROM criminal_cases_tx WHERE case_id = 1001 AND appearance_date LIKE '2019%';

ARTWORK(artwork_id, title, date_created, period, artist_id); ARTIST(artist_id, name, gender)
Q: Find the number of artworks in the 'modern' period and their respective artist's gender
A: SELECT COUNT(a.artwork_id), g.gender FROM ARTWORK a INNER JOIN ARTIST g ON a.artist_id = g.artist_id WHERE a.period = 'modern' GROUP BY g.gender;

CREATE TABLE products (id INT PRIMARY KEY, name VARCHAR(255), manufacturer_id INT, quantity INT, ethical_labor BOOLEAN);
Q: What is the total quantity of products manufactured using ethical labor practices?
A: SELECT SUM(quantity) FROM products WHERE ethical_labor = TRUE;

CREATE TABLE graduates (id INT, name VARCHAR(50), department VARCHAR(50), gpa DECIMAL(3,2)); INSERT INTO graduates (id, name, department, gpa) VALUES (1, 'Oliver Anderson', 'Computer Science', 3.6), (2, 'Zoe Davis', 'Mathematics', 3.9);
Q: Update the name of a student in the graduates table.
A: UPDATE graduates SET name = 'Olivia Anderson' WHERE id = 1;

CREATE TABLE co_owned_properties (property_id INT, size FLOAT); INSERT INTO co_owned_properties (property_id, size) VALUES (1, 1200.0), (2, 1500.0), (3, 1800.0);
Q: Identify the largest co-owned property in terms of size.
A: SELECT property_id, size FROM co_owned_properties ORDER BY size DESC LIMIT 1;

CREATE TABLE Warehouse (name varchar(20), pallets_handled int, handling_date date); INSERT INTO Warehouse (name, pallets_handled, handling_date) VALUES ('Warehouse J', 300, '2022-06-01');
Q: How many pallets were handled by 'Warehouse J' in 'June 2022'?
A: SELECT SUM(pallets_handled) FROM Warehouse WHERE name = 'Warehouse J' AND EXTRACT(MONTH FROM handling_date) = 6 AND EXTRACT(YEAR FROM handling_date) = 2022;

CREATE TABLE players (id INT, name VARCHAR(50), age INT, game_preference VARCHAR(20)); INSERT INTO players (id, name, age, game_preference) VALUES (1, 'Jane Kim', 28, 'VR'), (2, 'Park Ji-Soo', 31, 'Non-VR'), (3, 'Liam Chen', 22, 'VR');
Q: What is the average age of players who prefer VR games?
A: SELECT AVG(age) FROM players WHERE game_preference = 'VR';

CREATE SCHEMA if not exists bioprocess; USE bioprocess; CREATE TABLE if not exists engineering_projects (id INT PRIMARY KEY, project_name VARCHAR(255), budget FLOAT); INSERT INTO engineering_projects (id, project_name, budget) VALUES (1, 'Bio-Manufacturing Plant', 15000000.00), (2, 'Wastewater Treatment', 8000000.00), (3, 'Biofuel Production', 12000000.00);
Q: What is the minimum budget for bioprocess engineering projects in Europe?
A: SELECT MIN(budget) FROM bioprocess.engineering_projects WHERE region = 'Europe';

CREATE TABLE Country_Farms (country VARCHAR(255), num_farms INT); INSERT INTO Country_Farms (country, num_farms) VALUES ('Egypt', 75), ('Nigeria', 35), ('Kenya', 42), ('South Africa', 60), ('Tanzania', 53);
Q: Which African countries have more than 50 aquaculture farms?
A: SELECT Country_Farms.country FROM Country_Farms WHERE Country_Farms.num_farms > 50;

CREATE TABLE production (well_id INT, date DATE, quantity FLOAT, state VARCHAR(2)); INSERT INTO production (well_id, date, quantity, state) VALUES (1, '2021-01-01', 100.0, 'TX'), (1, '2021-01-02', 120.0, 'TX'), (2, '2021-01-01', 150.0, 'OK');
Q: Get the daily production for the past week for wells in the Permian Basin
A: SELECT well_id, date, quantity FROM production p JOIN wells w ON p.well_id = w.id WHERE w.state = 'TX' AND p.date >= DATEADD(day, -7, CURRENT_DATE);

CREATE TABLE refinery_table (rare_earth_element VARCHAR(20), year INT, production_volume INT);
Q: Insert a new record into the refinery_table for 'Promethium' with the given data: year = 2022, production_volume = 125
A: INSERT INTO refinery_table (rare_earth_element, year, production_volume) VALUES ('Promethium', 2022, 125);

CREATE TABLE Infrastructure (id INT, name VARCHAR(100), type VARCHAR(50), build_date DATE); INSERT INTO Infrastructure (id, name, type, build_date) VALUES (5, 'Hoover Dam', 'Dam', '1936-03-01'), (6, 'Glen Canyon Dam', 'Dam', '1966-09-13');
Q: Display the dams built before 1950
A: SELECT name FROM Infrastructure WHERE type = 'Dam' AND build_date < '1950-01-01';

CREATE TABLE songs (id INT, title TEXT, length FLOAT, genre TEXT); INSERT INTO songs (id, title, length, genre) VALUES (1, 'Song1', 120.0, 'Rock'), (2, 'Song2', 180.0, 'Pop'), (3, 'Song3', 240.0, 'Jazz'), (4, 'Song4', 90.0, 'Classical'), (5, 'Song5', 150.0, 'Hip-Hop'), (6, 'Song6', 210.0, 'Rock');
Q: How many unique genres are represented in the database?
A: SELECT COUNT(DISTINCT genre) FROM songs;

CREATE TABLE members (id INT, member_name VARCHAR(50), gender VARCHAR(50)); CREATE TABLE heart_rate (id INT, member_id INT, activity_type VARCHAR(50), heart_rate INT); INSERT INTO members (id, member_name, gender) VALUES (1, 'Jane Doe', 'Female'), (2, 'John Smith', 'Male'); INSERT INTO heart_rate (id, member_id, activity_type, heart_rate) VALUES (1, 1, 'yoga', 120), (2, 1, 'cardio', 140), (3, 2, 'yoga', 110), (4, 2, 'cardio', 130);
Q: What is the average heart rate for female members during 'yoga' workouts?'
A: SELECT AVG(heart_rate) AS avg_heart_rate FROM heart_rate JOIN members ON heart_rate.member_id = members.id WHERE activity_type = 'yoga' AND gender = 'Female';

CREATE TABLE factories(factory_id INT, name TEXT, location TEXT); CREATE TABLE workers(worker_id INT, name TEXT, salary DECIMAL, factory_id INT, program TEXT);
Q: Which factories do not have any workers in the workforce development program?
A: SELECT f.name FROM factories f LEFT JOIN workers w ON f.factory_id = w.factory_id WHERE w.program IS NULL;

CREATE SCHEMA if not exists ocean_shipping;CREATE TABLE if not exists ocean_shipping.cargo (id INT, status VARCHAR(255), arrived_at DATE);
Q: Update cargo status to 'delivered' if it has been at the destination for over a month
A: UPDATE ocean_shipping.cargo SET status = 'delivered' WHERE arrived_at < DATE_SUB(CURRENT_DATE, INTERVAL 30 DAY);

CREATE TABLE events (id INT, type VARCHAR(20)); INSERT INTO events (id, type) VALUES (1, 'Theater'), (2, 'Dance'), (3, 'Workshop'); CREATE TABLE attendees (id INT, event_id INT); INSERT INTO attendees (id, event_id) VALUES (1, 1), (2, 1), (3, 2), (1, 3), (4, 2);
Q: What is the total number of attendees for performing arts events and workshops, excluding repeat attendees?
A: SELECT COUNT(DISTINCT a.id) FROM attendees a JOIN events e ON a.event_id = e.id WHERE e.type IN ('Theater', 'Workshop');

CREATE TABLE volunteers (id INT, name VARCHAR(50), age INT, sessions_completed INT);
Q: What is the minimum age of volunteers in the volunteers table who have completed at least one training session?
A: SELECT MIN(age) FROM volunteers WHERE sessions_completed >= 1;

CREATE TABLE rural_projects (id INT, project_name VARCHAR(50), budget INT); INSERT INTO rural_projects (id, project_name, budget) VALUES (1, 'Drip Irrigation', 40000), (2, 'Solar Powered Pumps', 70000), (3, 'Organic Fertilizers', 30000);
Q: What are the names of all agricultural innovation projects in the 'rural_projects' table, excluding those with a budget over 50000?
A: SELECT project_name FROM rural_projects WHERE budget <= 50000;

CREATE TABLE bike_sharing (id INT, city VARCHAR(20), num_bikes INT); INSERT INTO bike_sharing (id, city, num_bikes) VALUES (1, 'Paris', 15000), (2, 'London', 12000);
Q: How many bicycles are there in the bike-sharing program in Paris?
A: SELECT num_bikes FROM bike_sharing WHERE city = 'Paris';

CREATE TABLE research_spending (id INT PRIMARY KEY, chemical_name VARCHAR(255), production_plant VARCHAR(255), research_spending_per_product DECIMAL(5,2)); INSERT INTO research_spending (id, chemical_name, production_plant, research_spending_per_product) VALUES (1, 'Hydrochloric Acid', 'Plant C', 5000); INSERT INTO research_spending (id, chemical_name, production_plant, research_spending_per_product) VALUES (2, 'Acetic Acid', 'Plant D', 6000);
Q: Find the average research spending per product for chemicals produced in Asian plants.
A: SELECT AVG(research_spending_per_product) FROM research_spending WHERE production_plant LIKE '%Asia%';

CREATE TABLE Samarium_Production (id INT, year INT, country VARCHAR(20), production_volume INT);
Q: What is the total production volume of Samarium in Canada and the USA combined?
A: SELECT SUM(production_volume) FROM Samarium_Production WHERE country IN ('Canada', 'USA');

CREATE TABLE investments (id INT, sector VARCHAR(255), amount FLOAT); INSERT INTO investments (id, sector, amount) VALUES (1, 'Social Impact Investing', 5000000.0), (2, 'Social Impact Investing', 7000000.0), (3, 'Renewable Energy', 8000000.0);
Q: What is the total amount of money invested in the social impact investing sector?
A: SELECT SUM(amount) FROM investments WHERE sector = 'Social Impact Investing';

CREATE TABLE policyholders (policyholder_id INT PRIMARY KEY, name VARCHAR(100), age INT, gender VARCHAR(10), city VARCHAR(50));
Q: Create a new table named 'policyholders_new' with columns 'policyholder_id', 'name', 'age', 'gender', 'city'
A: CREATE TABLE policyholders_new AS SELECT * FROM policyholders WHERE 1=2;

CREATE TABLE facility_scores (id INT, facility_name VARCHAR(255), score FLOAT); INSERT INTO facility_scores (id, facility_name, score) VALUES (1, 'Green Textiles', 8.5), (2, 'EcoMetal', 9.0), (3, 'SolarSteel', 9.5);
Q: What is the name of the facility with the highest circular economy score?
A: SELECT facility_name FROM facility_scores ORDER BY score DESC LIMIT 1;

CREATE TABLE fair_labor_practices (practice_id INT, brand_id INT, region TEXT, workers_benefitted INT); CREATE VIEW fair_labor_practices_summary AS SELECT region, SUM(workers_benefitted) AS total_workers FROM fair_labor_practices GROUP BY region;
Q: How many workers benefitted from fair labor practices in each region?
A: SELECT region, total_workers FROM fair_labor_practices_summary;

CREATE TABLE hotels (hotel_id INT, region VARCHAR(50), sustainability_level VARCHAR(50), revenue DECIMAL(10,2)); INSERT INTO hotels (hotel_id, region, sustainability_level, revenue) VALUES (1, 'Asia', 'Eco-Friendly', 12000.00), (2, 'Europe', 'Luxury', 15000.00), (3, 'Asia', 'Standard', 9000.00), (4, 'America', 'Eco-Friendly', 18000.00);
Q: What is the total revenue of eco-friendly hotels in Asia?
A: SELECT SUM(revenue) FROM hotels WHERE region = 'Asia' AND sustainability_level = 'Eco-Friendly';

CREATE TABLE co2_emissions (country VARCHAR(255), sector VARCHAR(255), year INT, co2_emissions INT); INSERT INTO co2_emissions VALUES ('India', 'Transportation', 2019, 356), ('India', 'Transportation', 2019, 358), ('India', 'Transportation', 2020, 345), ('India', 'Transportation', 2020, 348);
Q: Show the total CO2 emissions in India from the transportation sector in 2019 and 2020.
A: SELECT SUM(co2_emissions) FROM co2_emissions WHERE country = 'India' AND sector = 'Transportation' AND year IN (2019, 2020);

CREATE TABLE company_sales(company_name TEXT, sale_amount INT, sale_quarter INT, sale_year INT); INSERT INTO company_sales(company_name, sale_amount, sale_quarter, sale_year) VALUES('CompanyY', 4000, 3, 2019);
Q: What were the sales figures for 'CompanyY' in Q3 2019?
A: SELECT SUM(sale_amount) FROM company_sales WHERE company_name = 'CompanyY' AND sale_quarter = 3 AND sale_year = 2019;

CREATE TABLE warehouses (id INT, location VARCHAR(10), item VARCHAR(10), quantity INT); INSERT INTO warehouses (id, location, item, quantity) VALUES (1, 'NY', 'A101', 200), (2, 'NJ', 'A101', 300), (3, 'CA', 'B203', 150), (4, 'NY', 'C304', 50);
Q: What is the total quantity of items in warehouse 2 and 3?
A: SELECT SUM(quantity) FROM warehouses WHERE id IN (2, 3);

CREATE TABLE oil_fields(name VARCHAR(255), location VARCHAR(255), status VARCHAR(255));INSERT INTO oil_fields(name, location, status) VALUES('Gachsaran','Iran','Active'),('Ahwaz','Iran','Active'),('Marlin','Texas','Decommissioned'),('Endeavour','North Sea','Active'),('Ninian','North Sea','Decommissioned');
Q: What are the names of all oil fields that have been decommissioned in Texas or the North Sea?
A: SELECT name FROM oil_fields WHERE status = 'Decommissioned' AND (location = 'Texas' OR location = 'North Sea');

CREATE TABLE budget (id INT, category VARCHAR(255), year INT, amount FLOAT); INSERT INTO budget (id, category, year, amount) VALUES (1, 'Peacekeeping Operations', 2020, 7000000000);
Q: What was the budget for peacekeeping operations in 2020?
A: SELECT amount FROM budget WHERE category = 'Peacekeeping Operations' AND year = 2020;

CREATE TABLE sales_figures (quarter INT, drug_name VARCHAR(255), sales_amount FLOAT); INSERT INTO sales_figures (quarter, drug_name, sales_amount) VALUES (1, 'DrugB', 45000), (1, 'DrugA', 40000), (2, 'DrugA', 55000), (2, 'DrugB', 65000), (1, 'DrugAlpha', 35000);
Q: Update the name of DrugA to DrugAlpha in Q1 2017 sales figures.
A: UPDATE sales_figures SET drug_name = 'DrugAlpha' WHERE drug_name = 'DrugA' AND quarter = 1;

CREATE TABLE electric_vehicles (vehicle_id INT, vehicle_type VARCHAR(255), city VARCHAR(255), state VARCHAR(255));
Q: how many electric vehicles are there in Canada?
A: SELECT COUNT(*) FROM electric_vehicles WHERE state = 'Canada';

CREATE TABLE Donations (DonationID INT, DonorID INT, ProgramID INT, DonationAmount DECIMAL); INSERT INTO Donations (DonationID, DonorID, ProgramID, DonationAmount) VALUES (1, 1, 1, 150.00), (2, 2, 1, 120.00), (3, 3, 2, 90.00), (4, 1, 3, 100.00), (5, 4, 1, 160.00), (6, 1, 2, 180.00), (7, 2, 2, 130.00), (8, 3, 3, 110.00);
Q: Find the average donation amount for each program and the total number of donations for each program.
A: SELECT Programs.Name, AVG(Donations.DonationAmount) as AvgDonation, COUNT(Donations.DonationID) as TotalDonations FROM Programs JOIN Donations ON Programs.ProgramID = Donations.ProgramID GROUP BY Programs.Name;

CREATE TABLE network_towers (tower_id INT, location VARCHAR(100), longitude DECIMAL(9,6), latitude DECIMAL(9,6), height INT, installed_at TIMESTAMP);
Q: Insert a new network tower into the network_towers table
A: INSERT INTO network_towers (tower_id, location, longitude, latitude, height, installed_at) VALUES (4001, 'Downtown LA', -118.243683, 34.052235, 50, '2022-01-04 14:40:00');

CREATE TABLE cargo_ships (id INT, name VARCHAR(50), capacity INT, owner_id INT); INSERT INTO cargo_ships (id, name, capacity, owner_id) VALUES (1, 'Sea Titan', 150000, 1), (2, 'Ocean Marvel', 200000, 1), (3, 'Cargo Master', 120000, 2);
Q: Update the capacity of the cargo ship named 'Sea Titan' to 175,000.
A: UPDATE cargo_ships SET capacity = 175000 WHERE name = 'Sea Titan';

CREATE TABLE Volunteers (VolunteerID INT, VolunteerAge INT, VolunteerName TEXT); CREATE TABLE VolunteerEvents (EventID INT, ProgramID INT, EventDate DATE, VolunteerID INT);
Q: What is the total number of volunteers who engaged in programs in the past month, broken down by their age range?
A: SELECT CASE WHEN VolunteerAge < 18 THEN 'Under 18' WHEN VolunteerAge BETWEEN 18 AND 35 THEN '18-35' WHEN VolunteerAge BETWEEN 36 AND 54 THEN '36-54' ELSE '55 and Over' END AS AgeRange, COUNT(*) FROM Volunteers v INNER JOIN VolunteerEvents e ON v.VolunteerID = e.VolunteerID WHERE e.EventDate >= DATEADD(month, -1, GETDATE()) GROUP BY CASE WHEN VolunteerAge < 18 THEN 'Under 18' WHEN VolunteerAge BETWEEN 18 AND 35 THEN '18-35' WHEN VolunteerAge BETWEEN 36 AND 54 THEN '36-54' ELSE '55 and Over' END;

CREATE TABLE cases (case_id INT, category VARCHAR(20), billing_amount DECIMAL(10, 2));
Q: What is the average billing amount for cases in the criminal category?
A: SELECT AVG(billing_amount) FROM cases WHERE category = 'criminal';

CREATE TABLE student_accommodations (student_id INT, disability_type VARCHAR(255), country VARCHAR(255), date DATE, cost INT); INSERT INTO student_accommodations (student_id, disability_type, country, date, cost) VALUES (1, 'Mobility Impairment', 'USA', '2021-03-22', 500); INSERT INTO student_accommodations (student_id, disability_type, country, date, cost) VALUES (2, 'Mobility Impairment', 'Canada', '2021-04-01', 700);
Q: What is the total cost of accommodations for students with mobility impairments in the last 3 months?
A: SELECT SUM(cost) as total_cost FROM student_accommodations WHERE disability_type = 'Mobility Impairment' AND date BETWEEN DATE_SUB(NOW(), INTERVAL 3 MONTH) AND NOW();

CREATE TABLE autonomous_vehicles (id INT PRIMARY KEY, make VARCHAR(50), model VARCHAR(50), safety_rating FLOAT); INSERT INTO autonomous_vehicles (id, make, model, safety_rating) VALUES (1, 'Tesla', 'Model X', 9.2), (2, 'Waymo', 'Waymo One', 9.5), (3, 'NVIDIA', 'DRIVE AGX', 9.0), (4, 'Baidu', 'Apollo', 8.8), (5, 'Uber', 'ATG', 8.6);
Q: What's the average safety rating of all autonomous vehicles?
A: SELECT AVG(safety_rating) FROM autonomous_vehicles;

CREATE TABLE underrepresented_countries (company_name VARCHAR(100), founder_country VARCHAR(50), founding_year INT);
Q: Find the total number of startups founded by individuals from underrepresented countries
A: SELECT COUNT(*) FROM underrepresented_countries;

CREATE TABLE Events (Title TEXT, Date DATE, Location TEXT, Attendees INT);
Q: Insert a new record for an event with title 'Music Festival', date '2023-04-01', location 'City Park', and 500 attendees
A: INSERT INTO Events (Title, Date, Location, Attendees) VALUES ('Music Festival', '2023-04-01', 'City Park', 500);

CREATE TABLE EventPlayers (event VARCHAR(100), category VARCHAR(50), players INT);
Q: What is the average number of players per eSports event in the 'Strategy' category?
A: SELECT AVG(players) FROM EventPlayers WHERE category = 'Strategy';

CREATE TABLE Library(Year INT, Location VARCHAR(10), Number INT); INSERT INTO Library VALUES (2018, 'Urban', 15), (2018, 'Rural', 5), (2019, 'Urban', 18), (2019, 'Rural', 4), (2020, 'Urban', 20), (2020, 'Rural', 3);
Q: How many public libraries were there in urban areas in 2019?
A: SELECT SUM(Number) FROM Library WHERE Year = 2019 AND Location = 'Urban';

CREATE TABLE if not exists bike_trips (id INT, city VARCHAR(20), num_trips INT); INSERT INTO bike_trips (id, city, num_trips) VALUES (1, 'Beijing', 10000), (2, 'Shanghai', 8000);
Q: What is the total number of bike-sharing trips in Beijing?
A: SELECT num_trips FROM bike_trips WHERE city = 'Beijing';

CREATE TABLE readers (id INT, name VARCHAR(50), age INT, preference VARCHAR(50)); INSERT INTO readers (id, name, age, preference) VALUES (1, 'John Doe', 30, 'technology'), (2, 'Jane Smith', 45, 'sports'), (3, 'Bob Johnson', 28, 'politics'), (5, 'Aaliyah Patel', 32, 'international'); CREATE TABLE readers_preferences (reader_id INT, preference VARCHAR(50)); INSERT INTO readers_preferences (reader_id, preference) VALUES (1, 'technology'), (2, 'sports'), (3, 'politics'), (5, 'international');
Q: What is the average age of readers who prefer international news?
A: SELECT AVG(age) FROM readers INNER JOIN readers_preferences ON readers.id = readers_preferences.reader_id WHERE preference = 'international';

CREATE TABLE Bollywood_Movies (title TEXT, budget INTEGER); INSERT INTO Bollywood_Movies (title, budget) VALUES ('Movie1', 10000000), ('Movie2', 20000000), ('Movie3', 30000000), ('Movie4', 40000000), ('Movie5', 50000000), ('Movie6', 60000000);
Q: What is the maximum production budget of Bollywood movies?
A: SELECT MAX(budget) FROM Bollywood_Movies;

CREATE TABLE HealthBudget (Year INT, Service VARCHAR(255), Budget FLOAT); INSERT INTO HealthBudget VALUES (2018, 'Healthcare', 15000000), (2019, 'Healthcare', 16000000), (2020, 'Healthcare', ?);
Q: What is the total budget allocated for healthcare services in 2020?
A: SELECT SUM(Budget) FROM HealthBudget WHERE Service = 'Healthcare' AND Year = 2020;

CREATE TABLE concerts (concert_id INT, artist_id INT, genre VARCHAR(50), country VARCHAR(50), timestamp TIMESTAMP); INSERT INTO concerts (concert_id, artist_id, genre, country, timestamp) VALUES (1, 2001, 'Hip Hop', 'Japan', '2022-01-01 00:00:00'), (2, 2002, 'Hip Hop', 'China', '2022-01-02 12:30:00'); CREATE TABLE artists (artist_id INT, name VARCHAR(100)); INSERT INTO artists (artist_id, name) VALUES (2001, 'Kendrick Lamar'), (2002, 'Drake');
Q: What is the total number of concerts for the Hip Hop genre in Asia in the last 2 years?
A: SELECT COUNT(*) FROM concerts JOIN artists ON concerts.artist_id = artists.artist_id WHERE artists.genre = 'Hip Hop' AND concerts.country IN ('Japan', 'China', 'India', 'South Korea', 'Indonesia') AND concerts.timestamp >= '2020-01-01' AND concerts.timestamp < '2022-01-01';

CREATE TABLE garment_sales (id INT PRIMARY KEY, garment_id INT, quantity INT, sale_date DATE);
Q: What was the total quantity of garment 001 sold in 2022?
A: SELECT SUM(quantity) FROM garment_sales WHERE garment_id = 1 AND sale_date BETWEEN '2022-01-01' AND '2022-12-31';

CREATE TABLE workers (id INT, industry VARCHAR(255), salary FLOAT, union_member BOOLEAN); INSERT INTO workers (id, industry, salary, union_member) VALUES (1, 'Manufacturing', 50000.0, true), (2, 'Hospitality', 40000.0, true), (3, 'Retail', 30000.0, false);
Q: What is the total number of workers in the 'Hospitality' industry who are part of a union?
A: SELECT COUNT(*) FROM workers WHERE industry = 'Hospitality' AND union_member = true;

CREATE TABLE posts (post_id INT, user_id INT, content TEXT, likes INT, post_date DATE); INSERT INTO posts (post_id, user_id, content, likes, post_date) VALUES (1, 1, 'Hello World!', 15, '2022-01-01'), (2, 2, 'Nice weather today!', 5, '2022-01-05'), (3, 3, 'I love coding!', 35, '2022-01-03'), (4, 4, 'Excited for the weekend!', 12, '2022-01-07'), (5, 5, 'Just finished a project!', 28, '2022-01-02');
Q: Delete all posts with less than 10 likes and more than 30 days old from the "social_media" platform.
A: DELETE FROM posts WHERE likes < 10 AND post_date < DATE_SUB(CURRENT_DATE, INTERVAL 30 DAY);

CREATE TABLE threat_actors (id INT PRIMARY KEY, name VARCHAR(50), target_sector VARCHAR(50), success_count INT); INSERT INTO threat_actors (id, name, target_sector, success_count) VALUES (1, 'APT28', 'Healthcare', 20), (2, 'APT33', 'Healthcare', 18), (3, 'Magecart', 'Healthcare', 22);
Q: What are the top 5 threat actors with the highest number of successful attacks against healthcare organizations in the last 90 days, along with the total number of successful attacks for each?
A: SELECT name, success_count FROM threat_actors WHERE target_sector = 'Healthcare' AND success_count > 0 ORDER BY success_count DESC LIMIT 5;

CREATE TABLE hospitals (id INT, name TEXT, location TEXT, type TEXT); INSERT INTO hospitals (id, name, location, type) VALUES (1, 'Hospital A', 'City A, State A', 'Hospital'); INSERT INTO hospitals (id, name, location, type) VALUES (2, 'Clinic A', 'City B, State A', 'Clinic'); CREATE TABLE clinics (id INT, name TEXT, location TEXT, type TEXT); INSERT INTO clinics (id, name, location, type) VALUES (1, 'Clinic B', 'City A, State B', 'Clinic');
Q: What is the number of hospitals and clinics in rural areas, broken down by state?
A: SELECT h.state, COUNT(h.id) as hospital_count, COUNT(c.id) as clinic_count FROM hospitals h OUTER JOIN clinics c ON h.state = c.state WHERE h.location LIKE '%rural%' GROUP BY h.state;

CREATE TABLE tours (id INT, name TEXT, city TEXT, rating FLOAT); INSERT INTO tours (id, name, city, rating) VALUES (1, 'London Tour 1', 'London', 4.6), (2, 'London Tour 2', 'London', 4.7);
Q: What is the average rating of virtual tours in London?
A: SELECT AVG(rating) FROM tours WHERE city = 'London';

CREATE TABLE space_debris_monitoring (id INT, object_name VARCHAR(50), launch_country VARCHAR(50), launch_date DATE, latitude FLOAT, longitude FLOAT);
Q: Insert a new space debris record into the "space_debris_monitoring" table for an object launched by India in 2008.
A: INSERT INTO space_debris_monitoring (object_name, launch_country, launch_date, latitude, longitude) VALUES ('Debris_2008_India', 'India', '2008-01-01', 10.123456, 20.123456);

CREATE TABLE supplier_contracts (id INT, contract_id VARCHAR(50), supplier_id VARCHAR(50), contract_amount DECIMAL(10,2)); CREATE TABLE suppliers (id INT, supplier_id VARCHAR(50), supplier_name VARCHAR(100), industry VARCHAR(50));
Q: What are the top 10 suppliers with the highest revenue from defense contracts?
A: SELECT s.supplier_name, SUM(sc.contract_amount) AS revenue FROM supplier_contracts sc INNER JOIN suppliers s ON sc.supplier_id = s.supplier_id WHERE s.industry = 'Defense' GROUP BY s.supplier_name ORDER BY revenue DESC LIMIT 10;

CREATE TABLE graduate_students (id INT, name VARCHAR(50), advisor VARCHAR(50), grant INT); INSERT INTO graduate_students (id, name, advisor, grant) VALUES (1, 'Bob Brown', 'John Doe', 1), (2, 'Sara Connor', NULL, 0), (3, 'Mike White', 'Jane Smith', 1);
Q: List the graduate students who have received a research grant but do not have an advisor.
A: SELECT name FROM graduate_students WHERE grant = 1 AND advisor IS NULL;

CREATE TABLE Donors (DonorID INT, DonorName VARCHAR(50), LastDonationDate DATE);CREATE TABLE Causes (CauseID INT, CauseName VARCHAR(50));
Q: Which donors have not donated to any causes in the last 3 months?
A: SELECT D.DonorName FROM Donors D LEFT JOIN Causes C ON D.DonorID = C.DonorID WHERE C.DonorID IS NULL AND D.LastDonationDate < DATE_SUB(CURRENT_DATE, INTERVAL 3 MONTH);

CREATE TABLE customers (id INT, name VARCHAR(255), country VARCHAR(255)); INSERT INTO customers (id, name, country) VALUES (1, 'John Doe', 'USA'), (2, 'Jane Smith', 'Canada'), (3, 'Jim Brown', 'UK'); CREATE TABLE transactions (id INT, customer_id INT, amount DECIMAL(10, 2)); INSERT INTO transactions (id, customer_id, amount) VALUES (1, 1, 500.00), (2, 1, 750.00), (3, 2, 300.00), (4, 3, 1000.00), (5, 3, 1500.00);
Q: What is the total transaction amount for each customer from the United Kingdom?
