CREATE TABLE Equipment (EquipmentID INT, EquipmentType VARCHAR(50), Manufacturer VARCHAR(50), YearManufactured INT, Status VARCHAR(20));CREATE TABLE Repairs (RepairID INT, EquipmentID INT, RepairType VARCHAR(50), RepairCost DECIMAL(10,2), RepairDate DATE);CREATE VIEW QuarterlyEquipmentRepairs AS SELECT EquipmentID, ROW_NUMBER() OVER (PARTITION BY EquipmentID ORDER BY RepairDate DESC) AS QuarterRank, SUM(RepairCost) OVER (PARTITION BY EquipmentID, DATE_TRUNC('quarter', RepairDate)) AS QuarterlyRepairCost FROM Repairs;
Q: What is the total amount spent on equipment repairs per quarter, and which quarter has the highest repair spending?
