CREATE TABLE cultural_competency_training (worker_id INT, worker_name TEXT, community TEXT, training_hours INT); INSERT INTO cultural_competency_training (worker_id, worker_name, community, training_hours) VALUES (1, 'John Doe', 'White', 10), (2, 'Jane Smith', 'Black', 15), (3, 'Alice Johnson', 'Asian', 12), (4, 'Bob Brown', 'Hispanic', 18);
Q: What is the percentage of cultural competency training hours completed by community health workers from underrepresented communities?
A: SELECT 100.0 * SUM(CASE WHEN community IN ('Black', 'Asian', 'Hispanic') THEN training_hours ELSE 0 END) / SUM(training_hours) as percentage FROM cultural_competency_training;

CREATE TABLE suppliers (id INT, name VARCHAR(255), country VARCHAR(255)); CREATE TABLE products (id INT, name VARCHAR(255), organic BOOLEAN, weight FLOAT, supplier_id INT);
Q: Identify the top 3 heaviest non-organic products and their suppliers.
A: SELECT p.name, s.name as supplier, p.weight FROM suppliers s INNER JOIN products p ON s.id = p.supplier_id WHERE p.organic = 'f' ORDER BY p.weight DESC LIMIT 3;

