CREATE TABLE digital_assets (id INT, name VARCHAR(255), transaction_volume DECIMAL(10, 2)); INSERT INTO digital_assets (id, name, transaction_volume) VALUES (1, 'Asset 1', 1000.50), (2, 'Asset 2', 1500.25), (3, 'Asset 3', 2000.00); CREATE TABLE transactions (id INT, digital_asset_id INT, transaction_date DATE); INSERT INTO transactions (id, digital_asset_id, transaction_date) VALUES (1, 1, '2022-01-01'), (2, 2, '2022-01-05'), (3, 3, '2022-01-10');
Q: What's the total transaction volume for digital assets in the last month?
A: SELECT SUM(transaction_volume) FROM digital_assets JOIN transactions ON digital_assets.id = transactions.digital_asset_id WHERE transaction_date >= DATE_SUB(CURRENT_DATE, INTERVAL 1 MONTH);

