CREATE TABLE funding_records (id INT, company_id INT, funding_amount INT, funding_date DATE); CREATE TABLE companies (id INT, name TEXT, industry TEXT, founding_date DATE);
Q: Find the maximum and minimum funding amount for companies in the AI sector that have received funding in the last 2 years.
A: SELECT MAX(funding_amount), MIN(funding_amount) FROM funding_records JOIN companies ON funding_records.company_id = companies.id WHERE companies.industry = 'AI' AND funding_date BETWEEN DATE_SUB(CURRENT_DATE, INTERVAL 2 YEAR) AND CURRENT_DATE;

